INSERT INTO `tipologia` VALUES (1,'a.1.PC','interventi di trasformazione urbanistica ed edilizia del territorio quali a) nuove costruzione; b) ristrutturazione urbanistica; c) ristrutturazione edilizia che portino ad un organismo edilizio in tutto o in parte diverso dal precedente e che comportino modifiche della volumetria complessiva degli edifici o dei prospetti, ovvero che, limitatamente agli immobili compresi nelle zone omogenee A, comportino mutamenti della destinazione d\'uso, nonchÃ© gli interventi che comportino modificazioni della sagoma di immobili sottoposti a vincoli ai sensi del decreto legislativo 22 gennaio 2004, n. 42 e successive modificazioni.','art. 10 comma 1 d.P.R. 380/2001'),(2,'a.2.PC','interventi assoggettati a Segnalazione Certificata di Inizio AttivitÃ  per i quali Ã¨ facoltÃ  dellâavente titolo richiedere il rilascio del permesso di costruire','art. 22, comma 7 del d.P.R. n. 380/2001 '),(3,'a.3.PC','intervento giÃ  realizzato e conforme alla disciplina urbanistica ed edilizia vigente sia al momento della realizzazione, sia al momento della presentazione della richiesta','articolo 36, comma 1 del d.P.R. n. 380/2001'),(4,'a.4.PC','intervento in deroga alle previsioni degli strumenti di pianificazione urbanistica vigenti','art. 14 d.P.R. 380/2001'),(5,'a.5.PC','variazione essenziale e/o sostanziale',''),(6,'a.6.PC','attivitÃ  che rientrano nellâambito del procedimento ordinario dello sportello unico attivitÃ  produttive','articolo 7 del d.P.R. n. 160/2010'),(7,'a.7.PC','permesso di costruire convenzionato','articolo 28-bis, d.P.R. n. 380/2001'),(8,'a.8.PC','interventi di recupero abitativo dei sottotetti','l.r. Campania n. 15/2000 e l.r.19/09'),(9,'a.9.PC','realizzazione di parcheggi in aree libere','l.r. Campania n. 19/2001'),(10,'a.10.PC','mutamento di destinazione dâuso','l.r.Campania n. 19/2001'),(11,'a.11.PC','piano casa','l.r.Campania n. 19/2001'),(12,'c.1.SCIA','intervento di manutenzione straordinaria (pesante), restauro e risanamento conservativo (pesante) e ristrutturazione edilizia (leggera)','d.P.R. n. 380/2001, articolo 22, comma 1, articolo 3, comma 1, lett. b), c) e d). Punti 4, 6 e 7 della Sezione II â EDILIZIA â della Tabella A del d.lgs. 222/2016'),(13,'c.2.SCIA','intervento in corso di esecuzione, con pagamento di sanzione','articolo 37, comma 5, d.P.R. n. 380/2001'),(14,'c.3.SCIA','sanatoria dellâintervento realizzato conforme alla disciplina urbanistica ed edilizia vigente sia al momento della realizzazione, sia al momento della presentazione della segnalazione','d.P.R. n. 380/2001, articolo 37, comma 4. Punto 41 della Sezione II â EDILIZIA â della Tabella A del d.lgs. 222/2016'),(15,'c.4.SCIA','variante in corso dâopera a permesso di costruire che non incide sui parametri urbanistici e non costituisce variante essenziale','d.P.R. n. 380/2001, art. 22, commi 2, 2-bis. Punti 35 e 36 della Sezione II â EDILIZIA â della Tabella A del d.lgs. 222/2016'),(16,'c.5.SCIA','attivitÃ  che rientrano nellâambito del procedimento automatizzato dello sportello unico attivitÃ  produttive','arrt. 5 e 6 del d.P.R. n.160/2010'),(17,'c.6.SCIA','attivitÃ  che rientrano nellâambito del procedimento ordinario dello sportello unico attivitÃ  produttive','art. 7 del d.P.R. n.160/2010'),(18,'c.1.CILA','per la cui realizzazione non sono necessari altri atti di assenso, altre segnalazioni o comunicazioni',''),(19,'c.2.CILA','per la cui realizzazione presenta in allegato alla CILA le comunicazioni o segnalazioni certificate di inizio attivitÃ \nindicate nel quadro riepilogativo allegato',''),(20,'c.3.CILA','per la cui realizzazione presenta contestualmente alla CILA la domanda per lâacquisizione dâufficio degli atti assenso necessari alla realizzazione dellâintervento, indicati nel quadro riepilogativo allegato',''),(21,'c.1.SuperSCIA','interventi per i quali Ã¨ possibile presentare la SCIA alternativa al permesso di costruire','individuati dallâarticolo 23, del d.P.R. n. 380/